const term=document.getElementById('term'), read=document.getElementById('read'), c=document.getElementById('meter'), ctx=c.getContext('2d');function ease(t){return 1-Math.pow(1-t,3)}function tps(p){let v;if(p<.16)v=45+20*Math.sin(p*80);else if(p<.72){let u=(p-.16)/.56;v=80+728.7*ease(u)+18*Math.sin(p*70)}else v=808.7;return Math.max(0,Math.min(808.7,v))}function ang(v){return(-215+v/808.7*250)*Math.PI/180}function draw(v){c.width=c.clientWidth*devicePixelRatio;c.height=c.clientHeight*devicePixelRatio;ctx.setTransform(devicePixelRatio,0,0,devicePixelRatio,0,0);let w=c.clientWidth,h=c.clientHeight,cx=w/2,cy=h*.47,r=Math.min(w*.36,h*.27);ctx.clearRect(0,0,w,h);ctx.save();ctx.translate(cx,cy);ctx.lineCap='round';let g=ctx.createLinearGradient(-r,0,r,0);g.addColorStop(0,'#38bdf8');g.addColorStop(.55,'#22c55e');g.addColorStop(1,'#ef4444');ctx.beginPath();ctx.arc(0,0,r,ang(0),ang(808.7));ctx.strokeStyle='#334155';ctx.lineWidth=18;ctx.stroke();ctx.beginPath();ctx.arc(0,0,r,ang(0),ang(v));ctx.strokeStyle=g;ctx.lineWidth=18;ctx.shadowColor='#22c55e';ctx.shadowBlur=18;ctx.stroke();ctx.shadowBlur=0;for(let i=0;i<=16;i++){let val=808.7*i/16,a=ang(val),maj=i%4===0;ctx.beginPath();ctx.moveTo(Math.cos(a)*(r-(maj?34:22)),Math.sin(a)*(r-(maj?34:22)));ctx.lineTo(Math.cos(a)*(r+2),Math.sin(a)*(r+2));ctx.strokeStyle=maj?'#e5e7eb':'#64748b';ctx.lineWidth=maj?4:2;ctx.stroke();if(maj){ctx.fillStyle='#cbd5e1';ctx.font='700 15px system-ui';ctx.textAlign='center';ctx.fillText(Math.round(val),Math.cos(a)*(r-58),Math.sin(a)*(r-58))}}let a=ang(v);ctx.rotate(a);ctx.beginPath();ctx.moveTo(-18,-6);ctx.lineTo(r-42,0);ctx.lineTo(-18,6);ctx.closePath();ctx.fillStyle='#f43f5e';ctx.shadowColor='#fb7185';ctx.shadowBlur=16;ctx.fill();ctx.restore();read.textContent=v.toFixed(1).padStart(5,'0')}
